    public static string Up => $@"
CREATE TEMP TABLE _seed_categories ON COMMIT DROP AS
SELECT * FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(CATEGORIES_JSON)}$json$ AS jsonb)) AS x(
    id uuid,
    name text,
    description text,
    colorHex text,
    createdAtUtc timestamptz,
    updatedAtUtc timestamptz
);

INSERT INTO public.""Categories"" (""Id"",""Name"",""Description"",""ColorHex"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT id, name, description, colorHex, createdAtUtc, updatedAtUtc
FROM _seed_categories
ON CONFLICT (""Name"") DO UPDATE SET
    ""Description"" = EXCLUDED.""Description"",
    ""ColorHex"" = EXCLUDED.""ColorHex"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

CREATE TEMP TABLE _seed_printers ON COMMIT DROP AS
SELECT * FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(PRINTERS_JSON)}$json$ AS jsonb)) AS x(
    id uuid,
    name text,
    brand text,
    returnMonths numeric,
    machineCost numeric,
    workHoursPerDay numeric,
    workingDaysPerMonth numeric,
    powerKw numeric,
    usageLevel text,
    failureRate numeric,
    createdAtUtc timestamptz,
    updatedAtUtc timestamptz
);

INSERT INTO public.""PrinterProfiles"" (""Id"",""Name"",""Brand"",""ReturnMonths"",""MachineCost"",""WorkHoursPerDay"",""WorkingDaysPerMonth"",""PowerKw"",""UsageLevel"",""FailureRate"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT id, name, brand, returnMonths, machineCost, workHoursPerDay, workingDaysPerMonth, powerKw, usageLevel, failureRate, createdAtUtc, updatedAtUtc
FROM _seed_printers
ON CONFLICT (""Name"") DO UPDATE SET
    ""Brand"" = EXCLUDED.""Brand"",
    ""ReturnMonths"" = EXCLUDED.""ReturnMonths"",
    ""MachineCost"" = EXCLUDED.""MachineCost"",
    ""WorkHoursPerDay"" = EXCLUDED.""WorkHoursPerDay"",
    ""WorkingDaysPerMonth"" = EXCLUDED.""WorkingDaysPerMonth"",
    ""PowerKw"" = EXCLUDED.""PowerKw"",
    ""UsageLevel"" = EXCLUDED.""UsageLevel"",
    ""FailureRate"" = EXCLUDED.""FailureRate"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

CREATE TEMP TABLE _seed_filaments ON COMMIT DROP AS
SELECT * FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(FILAMENTS_JSON)}$json$ AS jsonb)) AS x(
    id uuid,
    name text,
    brand text,
    description text,
    spoolWeightKg numeric,
    spoolLengthMeters numeric,
    costBRL numeric,
    createdAtUtc timestamptz,
    updatedAtUtc timestamptz
);

INSERT INTO public.""FilamentProfiles"" (""Id"",""Name"",""Brand"",""Description"",""SpoolWeightKg"",""SpoolLengthMeters"",""CostBRL"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT id, name, brand, description, spoolWeightKg, spoolLengthMeters, costBRL, createdAtUtc, updatedAtUtc
FROM _seed_filaments
ON CONFLICT (""Name"") DO UPDATE SET
    ""Brand"" = EXCLUDED.""Brand"",
    ""Description"" = EXCLUDED.""Description"",
    ""SpoolWeightKg"" = EXCLUDED.""SpoolWeightKg"",
    ""SpoolLengthMeters"" = EXCLUDED.""SpoolLengthMeters"",
    ""CostBRL"" = EXCLUDED.""CostBRL"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

CREATE TEMP TABLE _seed_marketplaces ON COMMIT DROP AS
SELECT * FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(MARKETPLACES_JSON)}$json$ AS jsonb)) AS x(
    id uuid,
    name text,
    fixedFee numeric,
    percentageFee numeric,
    createdAtUtc timestamptz,
    updatedAtUtc timestamptz
);

INSERT INTO public.""MarketplaceFees"" (""Id"",""Name"",""FixedFee"",""PercentageFee"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT id, name, fixedFee, percentageFee, createdAtUtc, updatedAtUtc
FROM _seed_marketplaces
ON CONFLICT (""Name"") DO UPDATE SET
    ""FixedFee"" = EXCLUDED.""FixedFee"",
    ""PercentageFee"" = EXCLUDED.""PercentageFee"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

CREATE TEMP TABLE _seed_supplies ON COMMIT DROP AS
SELECT * FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(SUPPLIES_JSON)}$json$ AS jsonb)) AS x(
    id uuid,
    name text,
    unit text,
    costPerUnit numeric,
    stockQuantity numeric,
    minimumStock numeric,
    notes text,
    createdAtUtc timestamptz,
    updatedAtUtc timestamptz
);

INSERT INTO public.""Supplies"" (""Id"",""Name"",""Unit"",""CostPerUnit"",""StockQuantity"",""MinimumStock"",""Notes"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT id, name, unit, costPerUnit, stockQuantity, minimumStock, notes, createdAtUtc, updatedAtUtc
FROM _seed_supplies
ON CONFLICT (""Name"") DO UPDATE SET
    ""Unit"" = EXCLUDED.""Unit"",
    ""CostPerUnit"" = EXCLUDED.""CostPerUnit"",
    ""StockQuantity"" = EXCLUDED.""StockQuantity"",
    ""MinimumStock"" = EXCLUDED.""MinimumStock"",
    ""Notes"" = EXCLUDED.""Notes"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

CREATE TEMP TABLE _seed_products ON COMMIT DROP AS
SELECT * FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(PRODUCTS_JSON)}$json$ AS jsonb)) AS x(
    id uuid,
    recipeId uuid,
    recipeItemId uuid,
    name text,
    sku text,
    description text,
    categoryName text,
    costPrice numeric,
    salePrice numeric,
    suggestedPrice numeric,
    desiredMarkup numeric,
    currentStock numeric,
    minimumStock numeric,
    estimatedPrintTimeMinutes numeric,
    estimatedWeightGrams numeric,
    lengthMetersUsed numeric,
    tariffPerKwh numeric,
    finishingPercentage numeric,
    printerName text,
    filamentName text,
    marketplaceName text,
    compositionCost numeric,
    laborHours numeric,
    laborCostPerHour numeric,
    additionalCosts numeric,
    wholesaleMarkup numeric,
    retailMarkup numeric,
    resellerMarkup numeric,
    recipeItemQuantity numeric,
    createdAtUtc timestamptz,
    updatedAtUtc timestamptz
);

INSERT INTO public.""Products"" (
    ""Id"",""Name"",""Sku"",""Description"",""CategoryId"",""CostPrice"",""SalePrice"",""SuggestedPrice"",""ProfitMargin"",""CurrentStock"",""MinimumStock"",
    ""EstimatedPrintTimeMinutes"",""EstimatedWeightGrams"",""LengthMetersUsed"",""TariffPerKwh"",""FinishingPercentage"",""PrinterProfileId"",""FilamentProfileId"",
    ""DefaultMarketplaceFeeId"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT
    sp.id,
    sp.name,
    sp.sku,
    sp.description,
    c.""Id"",
    sp.costPrice,
    sp.salePrice,
    sp.suggestedPrice,
    CASE WHEN sp.salePrice <= 0 THEN 0 ELSE ROUND((sp.salePrice - sp.costPrice) / sp.salePrice, 4) END,
    sp.currentStock,
    sp.minimumStock,
    sp.estimatedPrintTimeMinutes,
    sp.estimatedWeightGrams,
    sp.lengthMetersUsed,
    sp.tariffPerKwh,
    sp.finishingPercentage,
    pp.""Id"",
    fp.""Id"",
    mf.""Id"",
    sp.createdAtUtc,
    sp.updatedAtUtc
FROM _seed_products sp
JOIN public.""Categories"" c ON c.""Name"" = sp.categoryName
LEFT JOIN public.""PrinterProfiles"" pp ON pp.""Name"" = sp.printerName
LEFT JOIN public.""FilamentProfiles"" fp ON fp.""Name"" = sp.filamentName
LEFT JOIN public.""MarketplaceFees"" mf ON mf.""Name"" = sp.marketplaceName
ON CONFLICT (""Sku"") DO UPDATE SET
    ""Name"" = EXCLUDED.""Name"",
    ""Description"" = EXCLUDED.""Description"",
    ""CategoryId"" = EXCLUDED.""CategoryId"",
    ""CostPrice"" = EXCLUDED.""CostPrice"",
    ""SalePrice"" = EXCLUDED.""SalePrice"",
    ""SuggestedPrice"" = EXCLUDED.""SuggestedPrice"",
    ""ProfitMargin"" = EXCLUDED.""ProfitMargin"",
    ""CurrentStock"" = EXCLUDED.""CurrentStock"",
    ""MinimumStock"" = EXCLUDED.""MinimumStock"",
    ""EstimatedPrintTimeMinutes"" = EXCLUDED.""EstimatedPrintTimeMinutes"",
    ""EstimatedWeightGrams"" = EXCLUDED.""EstimatedWeightGrams"",
    ""LengthMetersUsed"" = EXCLUDED.""LengthMetersUsed"",
    ""TariffPerKwh"" = EXCLUDED.""TariffPerKwh"",
    ""FinishingPercentage"" = EXCLUDED.""FinishingPercentage"",
    ""PrinterProfileId"" = EXCLUDED.""PrinterProfileId"",
    ""FilamentProfileId"" = EXCLUDED.""FilamentProfileId"",
    ""DefaultMarketplaceFeeId"" = EXCLUDED.""DefaultMarketplaceFeeId"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

INSERT INTO public.""ProductRecipes"" (
    ""Id"",""ProductId"",""LaborHours"",""LaborCostPerHour"",""AdditionalCosts"",""WholesaleMarkup"",""RetailMarkup"",""ResellerMarkup"",""TotalCost"",""CreatedAtUtc"",""UpdatedAtUtc"")
SELECT
    sp.recipeId,
    p.""Id"",
    sp.laborHours,
    sp.laborCostPerHour,
    sp.additionalCosts,
    sp.wholesaleMarkup,
    sp.retailMarkup,
    sp.resellerMarkup,
    sp.compositionCost,
    sp.createdAtUtc,
    sp.updatedAtUtc
FROM _seed_products sp
JOIN public.""Products"" p ON p.""Sku"" = sp.sku
ON CONFLICT (""ProductId"") DO UPDATE SET
    ""LaborHours"" = EXCLUDED.""LaborHours"",
    ""LaborCostPerHour"" = EXCLUDED.""LaborCostPerHour"",
    ""AdditionalCosts"" = EXCLUDED.""AdditionalCosts"",
    ""WholesaleMarkup"" = EXCLUDED.""WholesaleMarkup"",
    ""RetailMarkup"" = EXCLUDED.""RetailMarkup"",
    ""ResellerMarkup"" = EXCLUDED.""ResellerMarkup"",
    ""TotalCost"" = EXCLUDED.""TotalCost"",
    ""UpdatedAtUtc"" = EXCLUDED.""UpdatedAtUtc"";

DELETE FROM public.""ProductRecipeItems"" pri
USING public.""ProductRecipes"" pr, public.""Products"" p, _seed_products sp
WHERE pri.""ProductRecipeId"" = pr.""Id""
  AND pr.""ProductId"" = p.""Id""
  AND p.""Sku"" = sp.sku;

INSERT INTO public.""ProductRecipeItems"" (""Id"",""ProductRecipeId"",""SupplyId"",""Quantity"")
SELECT
    sp.recipeItemId,
    pr.""Id"",
    su.""Id"",
    sp.recipeItemQuantity
FROM _seed_products sp
JOIN public.""Products"" p ON p.""Sku"" = sp.sku
JOIN public.""ProductRecipes"" pr ON pr.""ProductId"" = p.""Id""
JOIN public.""Supplies"" su ON su.""Name"" = sp.filamentName
WHERE sp.recipeItemQuantity > 0;
";

    public static string Down => $@"
DELETE FROM public.""ProductRecipeItems"" pri
USING public.""ProductRecipes"" pr, public.""Products"" p
    WHERE pri.""ProductRecipeId"" = pr.""Id"" AND pr.""ProductId"" = p.""Id"" AND p.""Sku"" IN (SELECT sku FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(PRODUCTS_JSON)}$json$ AS jsonb)) AS x(sku text));
    DELETE FROM public.""ProductRecipes"" pr USING public.""Products"" p WHERE pr.""ProductId"" = p.""Id"" AND p.""Sku"" IN (SELECT sku FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(PRODUCTS_JSON)}$json$ AS jsonb)) AS x(sku text));
    DELETE FROM public.""Products"" WHERE ""Sku"" IN (SELECT sku FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(PRODUCTS_JSON)}$json$ AS jsonb)) AS x(sku text));
    DELETE FROM public.""Supplies"" WHERE ""Name"" IN (SELECT name FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(SUPPLIES_JSON)}$json$ AS jsonb)) AS x(name text));
    DELETE FROM public.""FilamentProfiles"" WHERE ""Name"" IN (SELECT name FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(FILAMENTS_JSON)}$json$ AS jsonb)) AS x(name text));
    DELETE FROM public.""PrinterProfiles"" WHERE ""Name"" IN (SELECT name FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(PRINTERS_JSON)}$json$ AS jsonb)) AS x(name text));
    DELETE FROM public.""MarketplaceFees"" WHERE ""Name"" IN (SELECT name FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(MARKETPLACES_JSON)}$json$ AS jsonb)) AS x(name text));
    DELETE FROM public.""Categories"" WHERE ""Name"" IN (SELECT name FROM jsonb_to_recordset(CAST($json${NormalizeJsonKeys(CATEGORIES_JSON)}$json$ AS jsonb)) AS x(name text));
";
}
